  const scroller = scrollama();
  scroller.setup({
    step: '#scrolly-claims .scrolly-step',
    offset: 0.5
  }).onStepEnter(({ index }) => {
    document.querySelectorAll('#scrolly-claims .scrolly-step').forEach((el, i) => {
      el.classList.toggle('is-active', i === index);
    });
    const d = claimData[index] || claimData[0];
    document.getElementById('claim-verdict').textContent = d.verdict;
    document.getElementById('claim-verdict').className = 'claim-verdict ' + d.cls;
    document.getElementById('claim-grade').innerHTML = d.grade || '';
    document.getElementById('claim-headline').textContent = d.headline;
    document.getElementById('claim-body').textContent = d.body;
  });
