function buildWaveViz(step) {
  const el = document.getElementById('wave-viz');
  if (!el) return;
  el.style.height = '340px';
  let chart = echarts.getInstanceByDom(el) || echarts.init(el);
  const isDark = document.documentElement.classList.contains('dark');
  const textColor = isDark ? '#ccc' : '#444';

  const migData = [
    { yr: '2021/22', total: 14168 },
    { yr: '2022/23', total: 27514 },
    { yr: '2023/24', total: 36891 },
    { yr: '2024/25', total: 18828 },
  ];

  const growthData = ENROLLMENT.grades.map((g, i) => ENROLLMENT.y2526[i] - ENROLLMENT.y2122[i]);

  let option = {};
  if (step === 0 || step === 1) {
    // Grade growth bars
    option = {
      backgroundColor: 'transparent',
      tooltip: { trigger: 'axis' },
      grid: { left: '3%', right: '5%', top: '5%', bottom: '15%', containLabel: true },
      xAxis: { type: 'category', data: ENROLLMENT.grades, axisLabel: { color: textColor, fontSize: 11 }, axisLine: { lineStyle: { color: isDark?'#555':'#ddd' } } },
      yAxis: { type: 'value', axisLabel: { color: textColor, formatter: v => v >= 1000 ? (v/1000).toFixed(0)+'k' : v }, splitLine: { lineStyle: { color: isDark?'#333':'#eee' } } },
      visualMap: { show: false, min: 0, max: 18000, inRange: {
        color: step === 1
          ? ENROLLMENT.grades.map((_, i) => i >= 2 && i <= 8 ? '#c0392b' : '#bbb')
          : ['#bbb', '#c0392b']
      }},
      series: [{
        type: 'bar',
        data: growthData.map((v, i) => ({
          value: v,
          itemStyle: {
            color: step === 1 ? (i >= 2 && i <= 8 ? '#c0392b' : '#ddd') : '#c0392b',
            borderRadius: [4,4,0,0]
          }
        })),
        barMaxWidth: 50,
        label: { show: true, position: 'top', color: textColor, formatter: p => '+'+p.value.toLocaleString(), fontSize: 10 }
      }]
    };
  } else if (step === 2) {
    // Migration bars
    option = {
      backgroundColor: 'transparent',
      tooltip: { trigger: 'axis' },
      title: { text: 'Net school-age migration into Alberta (ages 5–18)', textStyle: { color: textColor, fontSize: 13 }, top: 4 },
      grid: { left: '3%', right: '5%', top: '15%', bottom: '10%', containLabel: true },
      xAxis: { type: 'category', data: migData.map(d => d.yr), axisLabel: { color: textColor }, axisLine: { lineStyle: { color: isDark?'#555':'#ddd' } } },
      yAxis: { type: 'value', axisLabel: { color: textColor, formatter: v => (v/1000).toFixed(0)+'k' }, splitLine: { lineStyle: { color: isDark?'#333':'#eee' } } },
      series: [{
        type: 'bar', data: migData.map(d => d.total),
        itemStyle: { color: '#c0392b', borderRadius: [4,4,0,0] }, barMaxWidth: 60,
        label: { show: true, position: 'top', color: textColor, formatter: p => p.value.toLocaleString() }
      }]
    };
  } else {
    // ACOL comparison
    const current = ENROLLMENT.y2526.map((n, i) => {
      const classSize = 25;
      return Math.round(n / classSize);
    });
    option = {
      backgroundColor: 'transparent',
      tooltip: { trigger: 'axis' },
      title: { text: 'Implied classes needed vs ACOL target classes', textStyle: { color: textColor, fontSize: 12 }, top: 4 },
      legend: { data: ['Actual (at 25 students/class)','ACOL recommended'], textStyle: { color: textColor }, bottom: 0 },
      grid: { left: '3%', right: '3%', top: '15%', bottom: '15%', containLabel: true },
      xAxis: { type: 'category', data: ENROLLMENT.grades, axisLabel: { color: textColor, fontSize: 10 }, axisLine: { lineStyle: { color: isDark?'#555':'#ddd' } } },
      yAxis: { type: 'value', axisLabel: { color: textColor }, splitLine: { lineStyle: { color: isDark?'#333':'#eee' } } },
      series: [
        { name: 'Actual (at 25 students/class)', type: 'bar', data: current, itemStyle: { color: '#c0392b', borderRadius: [3,3,0,0] }, barGap: '-50%' },
        { name: 'ACOL recommended', type: 'bar', data: ENROLLMENT.y2526.map((n, i) => Math.round(n / ENROLLMENT.acol[i])), itemStyle: { color: '#2980b9', borderRadius: [3,3,0,0], opacity: 0.5 } }
      ]
    };
  }
  chart.setOption(option, true);
}

function initWaveScroll() {
  const scroller = scrollama();
  scroller.setup({
    step: '#scrolly-wave .scrolly-step',
    offset: 0.5
  }).onStepEnter(({ index }) => {
    document.querySelectorAll('#scrolly-wave .scrolly-step').forEach((el, i) => {
      el.classList.toggle('is-active', i === index);
    });
    buildWaveViz(index);
  });
}

// ══════════════════════════════════════════════
// SCHOOL MAP
// ══════════════════════════════════════════════

function buildMap() {
  const mapEl = document.getElementById('school-map');
  if (!mapEl) return;
  if (!window.L) {
    setTimeout(buildMap, 50);
    return;
  }
  if (mapEl.dataset.ready === 'true') return;
  mapEl.dataset.ready = 'true';

  const L = window.L;
  const map = L.map(mapEl, {
    zoomControl: true,
    scrollWheelZoom: false
  }).setView([53.2, -113.5], 5.5);

  L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
    attribution: '&copy; OpenStreetMap &copy; CARTO',
    maxZoom: 20
  }).addTo(map);

  const stageCounts = { construction: 0, design: 0, planning: 0 };

  SCHOOLS.forEach(s => {
    stageCounts[s.stage]++;
    const color = STAGE_COLORS[s.stage];
    const radius = s.stage === 'construction' ? 8 : s.stage === 'design' ? 6 : 5;

    L.circleMarker([s.lat, s.lng], {
      radius,
      color: '#ffffff',
      weight: 1.5,
      fillColor: color,
      fillOpacity: 0.9
    })
      .bindPopup(`<div style="font-family:sans-serif;font-size:12px;padding:2px 0;"><strong>${s.name}</strong><br><span style="color:${color};font-weight:600;text-transform:uppercase;font-size:10px;letter-spacing:0.05em;">${s.stage}</span><br><span style="color:#888;">${s.city}</span></div>`)
      .addTo(map);
  });

  const bounds = L.latLngBounds(SCHOOLS.map(s => [s.lat, s.lng]));
  map.fitBounds(bounds.pad(0.08));

  ['construction','design','planning'].forEach(stage => {
    const els = document.querySelectorAll(`.legend-item.${stage}`);
    els.forEach(el => {
      el.textContent = el.textContent.split('(')[0].trim() + ` (${stageCounts[stage]})`;
    });
  });
}

// ══════════════════════════════════════════════
// INIT
// ══════════════════════════════════════════════

document.addEventListener('DOMContentLoaded', () => {
  initClaimsScroll();
  initMathScroll();
  initWaveScroll();
  buildEnrollmentChart();
  buildWaveViz(0);
  buildMathChart(0);
  buildMap();
  scrollama().setup({ step: '.scrolly-step', offset: 0.5 }).onStepEnter(({ element }) => {
    element.classList.add('is-active');
  });
});
</script>
